      ></DirectMessageItem>
      <DirectMessageItem
        text="Eric"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
      ></DirectMessageItem>
      <DirectMessageItem
        text="Eric"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
      ></DirectMessageItem>
    </ul>
  );
};

export default DirectMessageList;
